            $.ajax({
                "async": true,
                "crossDomain": true,
                // "url": `https://sikumbang.tapera.go.id/ajax/lokasi/search?selectedSearch=wilayah&skalaPerumahan=semua&sort=terbaru&searchBy=nama-perumahan&page=${index}&limit=100`,
