                "method": "GET",
                "headers": {
                    "Accept": "*/*",
                },
                "success" : function(response){
                    myObject = response.count;
                    myObject['id_kec'] = id_kec[index];
                    data.push(myObject);
                    completedRequests++;
                },
                "complete" : function(response){
                    if (completedRequests === id_kec.length) {

                        setTimeout(() => {
                            console.info(data)
                            const jsonString = JSON.stringify(data);
                            createJsonFile(jsonString);
                        }, 1000);
                        
                    }
                }
            });

        }
        
